 ('256d9dcb-c7da-50de-938d-2665e9cece41','20000000-0000-0000-0000-000000000004','C1',25,$p$Precisión y matiz léxico: el término exacto$p$,'#6C3483','auto_stories')
insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('414efef7-1676-56b1-ba44-6a8042669d01','256d9dcb-c7da-50de-938d-2665e9cece41',1,$p$Sinónimos finos y sus matices (abitazione, osservare, apprezzare…)$p$,$p$Sinónimos finos y sus matices (abitazione, osservare, apprezzare…)$p$,'lesson',15),
 ('bbb61031-13f8-52e5-9730-aa044a2335ce','256d9dcb-c7da-50de-938d-2665e9cece41',2,$p$Colocaciones verbo + sustantivo (prendere una decisione, trarre una conclusione)$p$,$p$Colocaciones verbo + sustantivo (prendere una decisione, trarre una conclusione)$p$,'lesson',15),
 ('9253ae35-9663-55c9-ac2c-a502e208f25d','256d9dcb-c7da-50de-938d-2665e9cece41',3,$p$Registros: formale, colloquiale, familiare$p$,$p$Registros: formale, colloquiale, familiare$p$,'lesson',15),
 ('c81dfcc2-3a2e-5d26-bfda-f95fc03009f1','256d9dcb-c7da-50de-938d-2665e9cece41',4,$p$Precisión: anzi, addirittura, magari y expresiones fijas$p$,$p$Precisión: anzi, addirittura, magari y expresiones fijas$p$,'lesson',15),
 ('a41a9076-0684-5af7-be11-57afcda513b3','256d9dcb-c7da-50de-938d-2665e9cece41',5,$p$🏁 Checkpoint Unità 25$p$,$p$Demuestra que eliges el término exacto a nivel C1: distingues sinónimos finos y sus connotaciones (casa/abitazione/dimora/alloggio, guardare/osservare/scrutare/contemplare, adorare/apprezzare/gradire), dominas las colocaciones verbo+sustantivo (prendere una decisione, trarre una conclusione, nutrire una speranza, sollevare un dubbio), adaptas el registro (formale/colloquiale: automobile/macchina/auto) y evitas errores de precisión (magari, addirittura, anzi, tuttavia vs comunque).$p$,'checkpoint',40)
