('82d903f0-3e69-5e47-979b-570762514f26'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,'C1','reading','match',$p$Relaciona cada verbo con el sustantivo con el que forma la colocación fija correcta.$p$,$j${"pairs": [{"en": "prendere", "es": "una decisione"}, {"en": "trarre", "es": "una conclusione"}, {"en": "nutrire", "es": "una speranza"}, {"en": "sollevare", "es": "un dubbio"}]}$j$::jsonb,$j${"pairs": [["prendere", "una decisione"], ["trarre", "una conclusione"], ["nutrire", "una speranza"], ["sollevare", "un dubbio"]]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$collocazioni_match$p$, $p$reading$p$]),
