('185a7cc4-d6e1-5cf5-96a3-6b04893c5b01'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,'C1','writing','translation',$p$Traduce usando la colocación culta «trarre una conclusione»: «El investigador sacó una conclusión precipitada.» Emplea el passato prossimo.$p$,$j${"source": "El investigador sacó una conclusión precipitada."}$j$::jsonb,$j${"value": "Il ricercatore ha tratto una conclusione affrettata.", "accepted": ["Il ricercatore ha tratto una conclusione affrettata", "Il ricercatore ha tratto una conclusione affrettata.", "il ricercatore ha tratto una conclusione affrettata"]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$collocazioni_trarre_conclusione_translation$p$, $p$writing$p$]),
