('1888b759-785f-51d0-9ecb-8b107e60ca13'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,'C1','writing','translation',$p$Traduce al registro formal usando «invitare» y «dimora» (residencia, culta): «Nos invitó a su residencia.» Emplea el passato prossimo.$p$,$j${"source": "Nos invitó a su residencia."}$j$::jsonb,$j${"value": "Ci ha invitati nella sua dimora.", "accepted": ["Ci ha invitati nella sua dimora", "Ci ha invitati nella sua dimora.", "ci ha invitati nella sua dimora", "Ci ha invitato nella sua dimora."]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$registri_formale_dimora_translation$p$, $p$writing$p$]),
('47412414-53c5-56d0-8690-d464b89d3d40'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,'C1','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["Ha parcheggiato la macchina davanti a casa mia senza avvisare.", "Ha venduto la moto dietro la casa questa mattina.", "Ha lavato l'automobile davanti al garage ieri sera."], "say": "Ha parcheggiato la macchina davanti a casa mia senza avvisare.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/47412414-53c5-56d0-8690-d464b89d3d40.mp3"}$j$::jsonb,$j${"value": "Ha parcheggiato la macchina davanti a casa mia senza avvisare."}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$registri_listening$p$, $p$listening$p$]),
