 ('a026073e-2f78-592e-a2c6-36291c8986b3','20000000-0000-0000-0000-000000000004','C1',27,$p$Énfasis, puesta de relieve e inferencia$p$,'#7D3C98','format_quote')
insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('41dc6f8f-a150-5a94-a749-4143a2f216a0','a026073e-2f78-592e-a2c6-36291c8986b3',1,$p$Frasi scisse: è… che, è… a (è stato Marco a farlo)$p$,$p$Frasi scisse: è… che, è… a (è stato Marco a farlo)$p$,'lesson',15),
 ('85318f24-1b24-5fb3-aad3-e40f30695fb1','a026073e-2f78-592e-a2c6-36291c8986b3',2,$p$Dislocazione + messa in rilievo con proprio/perfino$p$,$p$Dislocazione + messa in rilievo con proprio/perfino$p$,'lesson',15),
 ('d9548515-b813-5dbf-a922-cb135ca723d2','a026073e-2f78-592e-a2c6-36291c8986b3',3,$p$Anteposizione stilistica + c'è… che$p$,$p$Anteposizione stilistica + c'è… che$p$,'lesson',15),
 ('31094622-4556-5643-8133-d106d056826d','a026073e-2f78-592e-a2c6-36291c8986b3',4,$p$Litote, inferenza y negazione enfatica (affatto/mica)$p$,$p$Litote, inferenza y negazione enfatica (affatto/mica)$p$,'lesson',15),
 ('9c112bae-8b27-581c-8e3e-7e1779de726b','a026073e-2f78-592e-a2c6-36291c8986b3',5,$p$🏁 Checkpoint Unità 27$p$,$p$Demuestra que dominas la puesta de relieve avanzada (frasi scisse «è stato Marco a farlo», «è qui che vivo», «è di questo che parlo»), la dislocazione a la izquierda/derecha con retoma pronominal («Il libro, l'ho letto», «A Roma ci vado spesso»), la enfatización con «proprio/perfino/persino», la anteposición estilística («Molto ho imparato», «Grande fu la sorpresa»), la estructura «c'è… che» y la inferencia/litote (non è male = è buono; non pochi = molti) con la negación enfática (non… affatto, non… mica, neanche per sogno).$p$,'checkpoint',40)
