 ('4bf1206d-4910-5df1-ba81-e90209f62623','20000000-0000-0000-0000-000000000004','C1',29,$p$Hipótesis y modalidad avanzada$p$,'#8E44AD','psychology_alt')
insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('f6020750-96d1-5fa2-8359-8a538e788d8b','4bf1206d-4910-5df1-ba81-e90209f62623',1,$p$Subordinadas hipotéticas cultas (qualora, a patto che / purché, a meno che… non)$p$,$p$Subordinadas hipotéticas cultas (qualora, a patto che / purché, a meno che… non)$p$,'lesson',15),
 ('f5171b14-13ad-5a98-9ef9-680cf6bd1d39','4bf1206d-4910-5df1-ba81-e90209f62623',2,$p$Nel caso in cui, ammesso che · periodo hipotético mixto$p$,$p$Nel caso in cui, ammesso che · periodo hipotético mixto$p$,'lesson',15),
 ('c7e594de-e1d1-5498-9806-2c53d08bba80','4bf1206d-4910-5df1-ba81-e90209f62623',3,$p$Condicional periodístico · potrebbe darsi che, non è escluso che$p$,$p$Condicional periodístico · potrebbe darsi che, non è escluso che$p$,'lesson',15),
 ('20fd09de-dacc-55b0-bd3c-ffadfead7ef9','4bf1206d-4910-5df1-ba81-e90209f62623',4,$p$Subjuntivo en relativas: il migliore che ci sia, cerco qualcuno che sappia$p$,$p$Subjuntivo en relativas: il migliore che ci sia, cerco qualcuno che sappia$p$,'lesson',15),
 ('806a56b5-b654-5bf3-a561-e5f0154f9ab1','4bf1206d-4910-5df1-ba81-e90209f62623',5,$p$🏁 Checkpoint Unità 29$p$,$p$Demuestra que manejas la hipótesis y la modalidad a nivel C1: encadenas subordinadas hipotéticas cultas (qualora + subj, a patto che / purché + subj, a meno che… non + subj, nel caso in cui + subj, ammesso che + subj), construyes el periodo hipotético mixto (Se avessi studiato, ora sarei laureato), reconoces el condicional de dissociazione/noticia no confirmada (Il ministro avrebbe dichiarato…), matizas la modalidad entre probabilidad y duda (potrebbe darsi che, non è escluso che, è probabile che + subj) y aplicas el subjuntivo en relativas con antecedente indefinido o superlativo (il migliore che ci sia, cerco qualcuno che sappia).$p$,'checkpoint',40)
