('92eb6ab1-e5d9-5517-b56c-348fdb95de2f'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,'C1','reading','match',$p$El periodo hipotético mixto combina un tiempo del pasado con una consecuencia en el presente. Relaciona cada frase con lo que expresa.$p$,$j${"pairs": [{"en": "Se avessi studiato, ora sarei laureato", "es": "condición irreal en el pasado, consecuencia en el presente"}, {"en": "Se fossi partito ieri, oggi saresti a casa", "es": "un hecho no realizado ayer con efecto en el hoy"}, {"en": "Se lo sapessi, te lo direi", "es": "hipótesis irreal enteramente en el presente"}]}$j$::jsonb,$j${"pairs": [["Se avessi studiato, ora sarei laureato", "condición irreal en el pasado, consecuencia en el presente"], ["Se fossi partito ieri, oggi saresti a casa", "un hecho no realizado ayer con efecto en el hoy"], ["Se lo sapessi, te lo direi", "hipótesis irreal enteramente en el presente"]]}$j$::jsonb,0.84,ARRAY[$p$unidad29$p$, $p$periodo_ipotetico_misto_match$p$, $p$reading$p$]),
