 ('dd0cddde-bd51-59ac-9455-bba4bac1116f','091d433a-6a62-518e-8424-a8d49a108642',1,$p$Nominalización (dimostrare → la dimostrazione, aumentare → l'aumento)$p$,$p$Nominalización (dimostrare → la dimostrazione, aumentare → l'aumento)$p$,'lesson',15),
 ('5d334d75-f129-530e-8668-527460d47495','091d433a-6a62-518e-8424-a8d49a108642',2,$p$Formas impersonales (si ritiene che, va rilevato che, ne consegue che)$p$,$p$Formas impersonales (si ritiene che, va rilevato che, ne consegue che)$p$,'lesson',15),
 ('e9abe02c-364a-59fb-8be1-f4ff497861df','091d433a-6a62-518e-8424-a8d49a108642',3,$p$Voz pasiva y fórmulas burocráticas (la presente, si prega di)$p$,$p$Voz pasiva y fórmulas burocráticas (la presente, si prega di)$p$,'lesson',15),
 ('9c00e49e-be1c-52bf-be85-743d6ca58746','091d433a-6a62-518e-8424-a8d49a108642',4,$p$Conectores académicos y correo formal (altresì, pertanto, per di più)$p$,$p$Conectores académicos y correo formal (altresì, pertanto, per di più)$p$,'lesson',15),
 ('1747523d-f0e6-51a7-92da-06f9aad5f2e1','091d433a-6a62-518e-8424-a8d49a108642',5,$p$🏁 Checkpoint Unità 30$p$,$p$Demuestra que redactas en registro formal y académico a nivel C1: nominalizas (dimostrare → la dimostrazione, aumentare → l'aumento, attuare → l'attuazione), empleas giros impersonales (si ritiene che, va rilevato che, ne consegue che, si evince che), dominas la voz pasiva y las fórmulas burocráticas (la presente ha lo scopo di…, si prega di trovare in allegato) y enlazas con conectores académicos (inoltre, pertanto, altresì, per di più, di conseguenza) en un correo profesional (Gentile…, Distinti saluti).$p$,'checkpoint',40)
